import json
d=json.load(open('/tmp/trivy_jars.json'))
seen={}
for r in d.get('Results') or []:
    for v in r.get('Vulnerabilities') or []:
        k=(v.get('PkgName'),v.get('InstalledVersion'))
        s=seen.setdefault(k,{'ids':set(),'sev':set(),'fixed':set()})
        s['ids'].add(v['VulnerabilityID']); s['sev'].add(v['Severity'])
        if v.get('FixedVersion'): s['fixed'].add(v['FixedVersion'])
print("distinct vuln (pkg,ver):",len(seen))
for (p,ver),i in sorted(seen.items()):
    print(f"{p} {ver} | sev={sorted(i['sev'])} | n={len(i['ids'])} | fixed={sorted(i['fixed'])}")
EOF

